-- ============================================================
-- SECTION D: UPDATE DATA WAREHOUSE
-- ============================================================

-- D1: New rooms to dim_room
SELECT R.room_id, R.room_no, R.room_type, R.capacity,
       F.floor_label, B.bld_name, B.bld_type, D.dept_name
FROM ROOM R
JOIN FLOOR      F ON R.floor_id    = F.floor_id
JOIN BUILDING   B ON F.building_id = B.building_id
JOIN DEPARTMENT D ON B.dept_id     = D.dept_id
WHERE R.room_id BETWEEN 201 AND 234;
GO

-- D2: New meters to dim_meter
SELECT M.meter_id, M.meter_type, R.room_no
FROM ENERGY_METER M
JOIN ROOM R ON M.room_id = R.room_id
WHERE M.meter_id BETWEEN 8 AND 41;
GO

-- D3: Load into fact table
SELECT
    CAST(FORMAT(CAST(E.timestamp AS DATE),'yyyyMMdd') AS INT),
    DR.room_key, DM.meter_key,
    E.kwh_consumed, E.voltage, E.peak_flag
FROM ENERGY_READING E
JOIN ENERGY_METER M  ON E.meter_id  = M.meter_id
JOIN dim_meter    DM ON DM.meter_id = M.meter_id
JOIN dim_room     DR ON DR.room_id  = M.room_id
WHERE M.meter_id BETWEEN 8 AND 41;
GO
PRINT 'Section D done: Warehouse updated.';
GO

-- ============================================================
-- SECTION E: FINAL VERIFICATION
-- ============================================================

SELECT DR.building_name,
       COUNT(DISTINCT DR.room_key)  AS rooms,
       ROUND(SUM(F.kwh_consumed),1) AS total_kwh
FROM fact_energy_consumption F
JOIN dim_room DR ON F.room_key = DR.room_key
GROUP BY DR.building_name
ORDER BY total_kwh DESC;

SELECT 'ROOM'          AS tbl, COUNT(*) AS rows FROM ROOM
UNION ALL SELECT 'ENERGY_METER',  COUNT(*) FROM ENERGY_METER
UNION ALL SELECT 'ENERGY_READING',COUNT(*) FROM ENERGY_READING
UNION ALL SELECT 'dim_room',      COUNT(*) FROM dim_room
UNION ALL SELECT 'dim_meter',     COUNT(*) FROM dim_meter
UNION ALL SELECT 'fact_energy_consumption', COUNT(*) FROM fact_energy_consumption;
GO
PRINT '=== ALL 6 BUILDINGS SEEDED SUCCESSFULLY ===';
GO